// types.ts
export interface Message {
  id:        string;
  role:      "user" | "assistant" | "system";
  content:   string;
  status:    "sending" | "streaming" | "done" | "error";
  createdAt: number;
}

export interface ChatState {
  messages:    Message[];
  isStreaming: boolean;
  pendingText: string;
  error:       string | null;
}

// useChatStream.ts
import { useCallback, useRef, useState } from "react";

export function useChatStream(apiUrl: string, authToken: string) {
  const [state, setState] = useState<ChatState>({
    messages: [], isStreaming: false, pendingText: "", error: null,
  });
  const abortRef = useRef<AbortController | null>(null);

  const send = useCallback(async (userText: string) => {
    const userMsg: Message = {
      id: crypto.randomUUID(), role: "user", content: userText,
      status: "done", createdAt: Date.now(),
    };
    const assistantPlaceholder: Message = {
      id: crypto.randomUUID(), role: "assistant", content: "",
      status: "streaming", createdAt: Date.now(),
    };

    setState(s => ({
      ...s, messages: [...s.messages, userMsg, assistantPlaceholder],
      isStreaming: true, pendingText: "", error: null,
    }));

    abortRef.current = new AbortController();

    try {
      const resp = await fetch(`${apiUrl}/v1/chat/completions`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${authToken}`,
        },
        body: JSON.stringify({
          messages: [...state.messages, userMsg].map(m => ({
            role: m.role, content: m.content,
          })),
        }),
        signal: abortRef.current.signal,
      });

      if (!resp.ok) {
        const err = await resp.json();
        throw new Error(err.detail ?? "Request failed");
      }

      const reader = resp.body!.getReader();
      const decoder = new TextDecoder();
      let accumulated = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const text = decoder.decode(value, { stream: true });
        // Parse SSE lines: "data: {...}"
        for (const line of text.split("\n")) {
          if (!line.startsWith("data: ")) continue;
          const payload = line.slice(6);
          if (payload === "[DONE]") break;
          const { delta } = JSON.parse(payload);
          accumulated += delta;
          setState(s => ({ ...s, pendingText: accumulated }));
        }
      }

      // Commit the complete message
      setState(s => ({
        ...s,
        messages: s.messages.map(m =>
          m.id === assistantPlaceholder.id
            ? { ...m, content: accumulated, status: "done" }
            : m
        ),
        isStreaming: false,
        pendingText: "",
      }));
    } catch (err: any) {
      if (err.name === "AbortError") {
        // User cancelled — keep partial response
        setState(s => ({
          ...s,
          messages: s.messages.map(m =>
            m.id === assistantPlaceholder.id
              ? { ...m, content: s.pendingText + " [cancelled]", status: "done" }
              : m
          ),
          isStreaming: false,
          pendingText: "",
        }));
      } else {
        setState(s => ({
          ...s, error: err.message, isStreaming: false,
          messages: s.messages.map(m =>
            m.id === assistantPlaceholder.id
              ? { ...m, status: "error" }
              : m
          ),
        }));
      }
    }
  }, [state.messages, apiUrl, authToken]);

  const stop = useCallback(() => {
    abortRef.current?.abort();
  }, []);

  return { state, send, stop };
}

// ConversationView.tsx
import { useEffect, useRef, useCallback } from "react";

interface Props {
  messages:    Message[];
  pendingText: string;
  isStreaming: boolean;
}

export function ConversationView({ messages, pendingText, isStreaming }: Props) {
  const bottomRef  = useRef<HTMLDivElement>(null);
  const atBottomRef = useRef(true);
  const containerRef = useRef<HTMLDivElement>(null);

  const onScroll = useCallback(() => {
    const el = containerRef.current;
    if (!el) return;
    const distFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
    atBottomRef.current = distFromBottom < 50;
  }, []);

  useEffect(() => {
    if (atBottomRef.current) {
      bottomRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [pendingText, messages.length]);

  return (
    <div ref={containerRef} onScroll={onScroll} className="overflow-y-auto flex-1 p-4">
      {messages.map(msg => (
        <MessageBubble key={msg.id} message={msg} />
      ))}
      {isStreaming && pendingText && (
        <MessageBubble
          message={{ id: "pending", role: "assistant", content: pendingText,
                     status: "streaming", createdAt: Date.now() }}
        />
      )}
      <div ref={bottomRef} />
    </div>
  );
}

// InputBar.tsx
import { useRef, useCallback } from "react";

interface Props {
  onSend:      (text: string) => void;
  onStop:      () => void;
  isStreaming: boolean;
}

export function InputBar({ onSend, onStop, isStreaming }: Props) {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const autoResize = useCallback(() => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = "auto";
    el.style.height = `${Math.min(el.scrollHeight, 200)}px`; // max 200px
  }, []);

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      const text = textareaRef.current?.value.trim() ?? "";
      if (text && !isStreaming) {
        onSend(text);
        if (textareaRef.current) {
          textareaRef.current.value = "";
          textareaRef.current.style.height = "auto";
        }
      }
    }
  }, [onSend, isStreaming]);

  return (
    <div className="border-t p-3 flex gap-2 items-end">
      <textarea
        ref={textareaRef}
        onInput={autoResize}
        onKeyDown={handleKeyDown}
        disabled={isStreaming}
        placeholder="Type a message… (Shift+Enter for newline)"
        rows={1}
        className="flex-1 resize-none rounded-lg border p-2 text-sm focus:outline-none"
      />
      {isStreaming ? (
        <button onClick={onStop} className="btn-danger">Stop</button>
      ) : (
        <button onClick={() => {
          const text = textareaRef.current?.value.trim() ?? "";
          if (text) onSend(text);
        }} className="btn-primary">Send</button>
      )}
    </div>
  );
}

// MessageBubble.tsx
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { Prism as SyntaxHighlighter } from "react-syntax-highlighter";
import { oneDark } from "react-syntax-highlighter/dist/esm/styles/prism";

function MarkdownContent({ content }: { content: string }) {
  return (
    <ReactMarkdown
      remarkPlugins={[remarkGfm]}
      components={{
        code({ inline, className, children }) {
          const language = /language-(\w+)/.exec(className ?? "")?.[1] ?? "text";
          return inline ? (
            <code className="bg-gray-800 rounded px-1 text-sm">{children}</code>
          ) : (
            <SyntaxHighlighter language={language} style={oneDark}>
              {String(children).replace(/\n$/, "")}
            </SyntaxHighlighter>
          );
        },
      }}
    >
      {content}
    </ReactMarkdown>
  );
}

export function MessageBubble({ message }: { message: Message }) {
  const isUser = message.role === "user";
  return (
    <div className={`flex ${isUser ? "justify-end" : "justify-start"} mb-4`}>
      <div className={`max-w-3xl rounded-lg px-4 py-3 ${
        isUser ? "bg-blue-600 text-white" : "bg-gray-800 text-gray-100"
      }`}>
        {isUser ? (
          <p className="whitespace-pre-wrap">{message.content}</p>
        ) : (
          <MarkdownContent content={message.content} />
        )}
        {message.status === "streaming" && (
          <span className="animate-pulse">▋</span>
        )}
      </div>
    </div>
  );
}
